prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?org ?orgName ?orgId WHERE {
  ?org a bboExt:Organization .
  ?org tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .
  OPTIONAL { ?org rdfs:label ?orgName . }
  OPTIONAL { ?org bbo:name ?orgName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?created WHERE {
  ?model a bboExt:Model .
  ?model tai:belongsTo <https://www.teamingai-project.eu/kg/organization/Org25> .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:modelCreated ?created . }
}
LIMIT 50

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
# Explore participants to understand how customer is represented
SELECT ?participant ?partName ?partType WHERE {
  ?participant a bboExt:Participant .
  OPTIONAL { ?participant bbo:name ?partName . }
  OPTIONAL { ?participant a ?partType . }
  FILTER(CONTAINS(LCASE(STR(?partName)), "customer") || CONTAINS(LCASE(STR(?partName)), "kunde"))
}
LIMIT 25
